#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard escapeHTML);

my $q = CGI->new;
my $log_dir = '/var/log';

print $q->header('text/html; charset=UTF-8');
print "<!DOCTYPE html><html><head><title>Log Viewer</title></head><body>";

my $filename = $q->param('logfile') // '';

print "<h1>Log Viewer</h1>";
print "<p>Requested log: " . escapeHTML($filename) . "</p>";
print "<pre>";

if ($filename ne '' && open(FH, "$log_dir/$filename")) {
    while (my $line = <FH>) {
        print escapeHTML($line);
    }
    close(FH);
} else {
    print "Unable to open log file.\n";
}

print "</pre>";
print "</body></html>";